router.get("/products/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const result = getProductById(id);
  if (!result) { res.status(404).json({ error: "Product not found" }); return; }
  res.json(result);
});

// PATCH /products/:id/stock — validate adjustment type (HTTP concern),
//   catch NotFoundError→404, ValidationError→400
router.patch("/products/:id/stock", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const { adjustment } = req.body as { adjustment: number };
